/**
 * @summary Search meals across all restaurants
 */
export const getSearchMealsUrl = (params: SearchMealsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/search/meals?${stringifiedParams}`
    : `/api/search/meals`;
};

export const searchMeals = async (
  params: SearchMealsParams,
  options?: RequestInit,
): Promise<PopularMeal[]> => {
  return customFetch<PopularMeal[]>(getSearchMealsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchMealsQueryKey = (params?: SearchMealsParams) => {
  return [`/api/search/meals`, ...(params ? [params] : [])] as const;
};

export const getSearchMealsQueryOptions = <
  TData = Awaited<ReturnType<typeof searchMeals>>,
  TError = ErrorType<unknown>,
>(
  params: SearchMealsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchMeals>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getSearchMealsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof searchMeals>>> = ({
    signal,
  }) => searchMeals(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof searchMeals>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type SearchMealsQueryResult = NonNullable<
  Awaited<ReturnType<typeof searchMeals>>
>;
export type SearchMealsQueryError = ErrorType<unknown>;

/**
 * @summary Search meals across all restaurants
 */

export function useSearchMeals<
  TData = Awaited<ReturnType<typeof searchMeals>>,
  TError = ErrorType<unknown>,
>(
  params: SearchMealsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchMeals>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getSearchMealsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
